  margin-bottom: 16px !important;
  border-bottom: 1px solid #eee8dc !important;
}

.hg-review-item {
  padding: 14px 0 !important;
  border-bottom: 1px solid #eee8dc !important;
}

.hg-review-item:last-child {
  border-bottom: none !important;
}

#hg-reviews-fallback button,
.hg-reviews-content button[class*="load"],
.hg-reviews-content [class*="Load"],
.hg-review-list + button,
.hg-review-list ~ button,
button.hg-load-more {
  width: 100% !important;
  padding: 13px !important;
  border: 2px solid #2c5530 !important;
  border-radius: 8px !important;
  background: transparent !important;
  color: #2c5530 !important;
